function _has_illegal_chars(str) {
	return /[^a-z0-9\:\/\?\#\[\]\@\!\$\&\'\(\)\*\+\,\;\=\.\-\_\~\%]/i.test(str);
}

function parse(currentUrlStr, baseUrlStr) {
	let ret = {
		url: null,
		baseurl: null,
		protocol: null,
		host: null,
		domain: null,
		subdomain: null,
		path: null,
		search: null,
		querycount: 0
